"use client"

import * as React from "react"
import Link from "next/link"
import { motion, useScroll, useMotionValueEvent } from "framer-motion"
import { Menu, X, Play } from "lucide-react"

const LINKS = ["Work", "Studio", "Motion", "Contact"]

/**
 * Kinetic header — a bar that compresses on scroll, with underline-sweep nav links.
 */
export function HeaderKinetic() {
  const [open, setOpen] = React.useState(false)
  const [scrolled, setScrolled] = React.useState(false)
  const { scrollY } = useScroll()

  useMotionValueEvent(scrollY, "change", (y) => setScrolled(y > 12))

  return (
    <header className="sticky top-0 z-40 bg-background/85 text-foreground backdrop-blur-md">
      <motion.div
        animate={{ paddingTop: scrolled ? 10 : 20, paddingBottom: scrolled ? 10 : 20 }}
        transition={{ type: "spring", stiffness: 320, damping: 32 }}
        className="mx-auto flex max-w-6xl items-center justify-between border-b border-border px-5 sm:px-8"
      >
        <Link href="#" className="flex items-center gap-2">
          <span className="grid size-8 place-items-center rounded-[var(--radius)] bg-primary text-primary-foreground">
            <Play className="size-4" />
          </span>
          <span className="text-xl font-black tracking-tight uppercase">Tempo</span>
        </Link>

        <nav className="hidden items-center gap-8 md:flex">
          {LINKS.map((l) => (
            <Link
              key={l}
              href="#"
              className="group relative text-sm font-semibold text-foreground"
            >
              {l}
              <span className="absolute -bottom-1 left-0 h-0.5 w-full origin-left scale-x-0 bg-primary transition-transform duration-300 group-hover:scale-x-100" />
            </Link>
          ))}
        </nav>

        <div className="flex items-center gap-3">
          <Link
            href="#"
            className="hidden rounded-full bg-foreground px-5 py-2 text-sm font-semibold text-background transition-transform hover:-translate-y-0.5 sm:block"
          >
            Start a project
          </Link>
          <button onClick={() => setOpen((o) => !o)} aria-label="Menu" className="md:hidden">
            {open ? <X className="size-6" /> : <Menu className="size-6" />}
          </button>
        </div>
      </motion.div>

      {open && (
        <nav className="grid border-b border-border md:hidden">
          {LINKS.map((l) => (
            <Link
              key={l}
              href="#"
              className="border-b border-border px-5 py-3 text-sm font-semibold last:border-b-0"
            >
              {l}
            </Link>
          ))}
        </nav>
      )}
    </header>
  )
}

"use client"

import * as React from "react"
import Link from "next/link"
import { motion, useReducedMotion, type Variants } from "framer-motion"
import { ArrowUpRight, Sparkles } from "lucide-react"

const HEADLINE = ["Motion", "that", "makes", "people", "stop", "scrolling."]
const MARQUEE = ["Brand films", "Title design", "Product motion", "Explainers", "Loops", "3D & 2D"]

const container: Variants = {
  hidden: {},
  show: { transition: { staggerChildren: 0.06, delayChildren: 0.1 } },
}
const word: Variants = {
  hidden: { y: "110%" },
  show: { y: 0, transition: { type: "spring", stiffness: 420, damping: 32 } },
}

/** A button that leans toward the cursor — the signature kinetic micro-interaction. */
function MagneticLink({
  children,
  className,
}: {
  children: React.ReactNode
  className?: string
}) {
  const ref = React.useRef<HTMLAnchorElement>(null)
  const reduce = useReducedMotion()
  const [pos, setPos] = React.useState({ x: 0, y: 0 })

  function onMove(e: React.MouseEvent) {
    if (reduce || !ref.current) return
    const r = ref.current.getBoundingClientRect()
    setPos({ x: (e.clientX - (r.left + r.width / 2)) * 0.3, y: (e.clientY - (r.top + r.height / 2)) * 0.3 })
  }

  return (
    <motion.a
      ref={ref}
      href="#"
      onMouseMove={onMove}
      onMouseLeave={() => setPos({ x: 0, y: 0 })}
      animate={{ x: pos.x, y: pos.y }}
      transition={{ type: "spring", stiffness: 260, damping: 18 }}
      className={className}
    >
      {children}
    </motion.a>
  )
}

/**
 * Kinetic hero — an oversized headline whose words spring up into place, a looping
 * service marquee, and a magnetic primary CTA.
 */
export function HeroKinetic() {
  const reduce = useReducedMotion()

  return (
    <section className="relative overflow-hidden bg-background text-foreground">
      <div className="mx-auto max-w-6xl px-5 py-20 sm:px-8 sm:py-28">
        <motion.span
          initial={{ opacity: 0, y: 10 }}
          animate={{ opacity: 1, y: 0 }}
          className="inline-flex items-center gap-2 rounded-full border border-border bg-card px-4 py-1.5 text-xs font-semibold tracking-wide uppercase"
        >
          <Sparkles className="size-3.5 text-primary" /> Tempo — motion design studio
        </motion.span>

        <motion.h1
          variants={reduce ? undefined : container}
          initial={reduce ? undefined : "hidden"}
          animate={reduce ? undefined : "show"}
          className="mt-7 flex max-w-4xl flex-wrap gap-x-4 text-[clamp(2.75rem,9vw,6.5rem)] font-black leading-[0.92] tracking-tight"
        >
          {HEADLINE.map((w, i) => (
            <span key={i} className="overflow-hidden pb-[0.08em]">
              <motion.span
                variants={reduce ? undefined : word}
                className={`inline-block ${w === "stop" ? "text-primary" : ""}`}
              >
                {w}
              </motion.span>
            </span>
          ))}
        </motion.h1>

        <div className="mt-9 flex flex-col gap-6 sm:flex-row sm:items-center">
          <p className="max-w-md text-lg text-muted-foreground">
            We design title sequences, brand films, and product motion that earn a second look.
          </p>
          <div className="flex flex-wrap items-center gap-4">
            <MagneticLink className="inline-flex items-center gap-2 rounded-full bg-primary px-7 py-3.5 text-sm font-bold text-primary-foreground">
              See the reel <ArrowUpRight className="size-4" />
            </MagneticLink>
            <Link href="#" className="text-sm font-semibold underline-offset-4 hover:underline">
              Our process
            </Link>
          </div>
        </div>
      </div>

      {/* looping service marquee */}
      <div className="overflow-hidden border-y border-border bg-foreground py-4 text-background">
        <motion.div
          animate={reduce ? undefined : { x: ["0%", "-50%"] }}
          transition={{ duration: 18, repeat: Infinity, ease: "linear" }}
          className="flex w-max gap-10 whitespace-nowrap text-2xl font-black tracking-tight uppercase sm:text-3xl"
        >
          {[...MARQUEE, ...MARQUEE].map((m, i) => (
            <span key={i} className="flex items-center gap-10">
              {m} <span className="text-primary">✳</span>
            </span>
          ))}
        </motion.div>
      </div>
    </section>
  )
}

"use client"

import * as React from "react"
import { motion, useInView, useReducedMotion, useSpring, useTransform } from "framer-motion"
import { Film, Layers, Gauge, Wand2 } from "lucide-react"

/** Counts a number up from 0 once it scrolls into view. */
function CountUp({ to, suffix = "" }: { to: number; suffix?: string }) {
  const ref = React.useRef<HTMLSpanElement>(null)
  const inView = useInView(ref, { once: true, margin: "-60px" })
  const reduce = useReducedMotion()
  const spring = useSpring(0, { stiffness: 60, damping: 18 })
  const text = useTransform(spring, (v) => `${Math.round(v)}${suffix}`)

  React.useEffect(() => {
    if (!inView) return
    if (reduce) spring.jump(to)
    else spring.set(to)
  }, [inView, reduce, spring, to])

  return <motion.span ref={ref}>{text}</motion.span>
}

const reveal = {
  hidden: { opacity: 0, y: 24 },
  show: (i: number) => ({
    opacity: 1,
    y: 0,
    transition: { type: "spring" as const, stiffness: 260, damping: 28, delay: i * 0.08 },
  }),
}

/**
 * Kinetic bento — a capability grid that springs in on scroll, lifts on hover, and
 * features one live count-up metric.
 */
export function BentoKinetic() {
  const reduce = useReducedMotion()

  const cells = [
    {
      span: "sm:col-span-2 sm:row-span-2",
      body: (
        <>
          <Film className="size-7 text-primary" />
          <h3 className="mt-auto text-3xl font-black tracking-tight">Brand films</h3>
          <p className="mt-2 text-muted-foreground">
            From script to final grade — story-led films built to move.
          </p>
        </>
      ),
    },
    {
      span: "",
      body: (
        <>
          <Layers className="size-6 text-accent" />
          <p className="mt-auto text-5xl font-black tracking-tight tabular-nums">
            <CountUp to={240} suffix="+" />
          </p>
          <p className="text-sm text-muted-foreground">projects shipped</p>
        </>
      ),
    },
    {
      span: "",
      body: (
        <>
          <Gauge className="size-6 text-primary" />
          <p className="mt-auto text-5xl font-black tracking-tight tabular-nums">
            <CountUp to={18} suffix="d" />
          </p>
          <p className="text-sm text-muted-foreground">avg. turnaround</p>
        </>
      ),
    },
    {
      span: "sm:col-span-2",
      body: (
        <>
          <Wand2 className="size-6 text-accent" />
          <h3 className="mt-auto text-2xl font-black tracking-tight">Title & product motion</h3>
          <p className="mt-2 text-muted-foreground">
            Sequences, UI motion, and loops tuned frame by frame.
          </p>
        </>
      ),
    },
  ]

  return (
    <section className="bg-background px-5 py-20 text-foreground sm:px-8">
      <div className="mx-auto max-w-6xl">
        <h2 className="max-w-2xl text-[clamp(1.9rem,5vw,3rem)] font-black leading-tight tracking-tight">
          A studio built for everything that moves.
        </h2>

        <div className="mt-10 grid auto-rows-[180px] gap-4 sm:grid-cols-3">
          {cells.map((c, i) => (
            <motion.div
              key={i}
              custom={i}
              variants={reduce ? undefined : reveal}
              initial={reduce ? undefined : "hidden"}
              whileInView={reduce ? undefined : "show"}
              viewport={{ once: true, margin: "-40px" }}
              whileHover={reduce ? undefined : { y: -6 }}
              className={`flex flex-col rounded-[calc(var(--radius)+4px)] border border-border bg-card p-6 ${c.span}`}
            >
              {c.body}
            </motion.div>
          ))}
        </div>
      </div>
    </section>
  )
}

